1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_DISCOUNT = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
6	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
7	const BLOCK_OF_THREE_DISCOUNT = 15;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	type QuoteStep = { op: "quote"; items: Array<Item> };
20	type Damage = { itemType: string; amount: number };
21	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
22	type Step = QuoteStep | ClaimStep;
23	type Customer = { yearsWithMHPCO: number };
24	type Scenario = {
25	  customer: Customer;
26	  steps: Array<Step>;
27	};
28	
29	const DEDUCTIBLE = 100;
30	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
31	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
32	
33	const roundDownInMHPCOFavor = (amount: number): number =>
34	  Math.floor(amount + FLOAT_ROUNDING_TOLERANCE);
35	
36	const roundUpInMHPCOFavor = (amount: number): number =>
37	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
38	
39	const HIGH_ENCHANTMENT_THRESHOLD = 5;
40	
41	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
42	
43	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
44	
45	const ITEM_SURCHARGES: Array<ItemSurcharge> = [
46	  { applies: (item) => item.cursed === true, rate: 0.5 },
47	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: 0.3 },
48	];
49	
50	const surchargesFor = (item: Item): number =>
51	  ITEM_SURCHARGES.reduce(
52	    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumOf(item) * rate : 0),
53	    0,
54	  );
55	
56	const sumOfBasePrices = (items: Array<Item>): number =>
57	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
58	
59	const sumOfItemSurcharges = (items: Array<Item>): number =>
60	  items.reduce((sum, item) => sum + surchargesFor(item), 0);
61	
62	const COMPONENT_TYPES = ["rune", "moonstone"];
63	const BLOCK_SIZE = 3;
64	
65	const countOfType = (items: Array<Item>, type: string): number =>
66	  items.filter((item) => item.type === type).length;
67	
68	const formsABlock = (items: Array<Item>, type: string): boolean =>
69	  countOfType(items, type) === BLOCK_SIZE;
70	
71	const blockDiscountFor = (items: Array<Item>): number =>
72	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
73	  BLOCK_OF_THREE_DISCOUNT;
74	
75	const basePremiumFor = (items: Array<Item>): number =>
76	  sumOfBasePrices(items) - blockDiscountFor(items);
77	
78	type PolicyContext = { customer: Customer; isFollowUp: boolean };
79	type PolicyAdjustment = { applies: (ctx: PolicyContext) => boolean; signedRate: number };
80	
81	const POLICY_ADJUSTMENTS: Array<PolicyAdjustment> = [
82	  { applies: () => true, signedRate: +FIRST_INSURANCE_SURCHARGE },
83	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, signedRate: -LOYALTY_DISCOUNT },
84	  { applies: ({ isFollowUp }) => isFollowUp, signedRate: -FOLLOW_UP_CONTRACT_DISCOUNT },
85	];
86	
87	const policyAdjustmentsOn = (policyBase: number, ctx: PolicyContext): number =>
88	  POLICY_ADJUSTMENTS.reduce(
89	    (sum, { applies, signedRate }) => sum + (applies(ctx) ? policyBase * signedRate : 0),
90	    0,
91	  );
92	
93	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
94	  const policyBase = basePremiumFor(step.items);
95	  const premiumBeforeRounding =
96	    policyBase
97	    + policyAdjustmentsOn(policyBase, ctx)
98	    + sumOfItemSurcharges(step.items)
99	    + PROCESSING_FEE;
100	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
101	};
102	
103	const findInsuredItem = (policy: QuoteStep, itemType: string): Item =>
104	  policy.items.find((item) => item.type === itemType)!;
105	
106	const reimbursementOf = (item: Item, damage: Damage): number =>
107	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
108	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
109	    : damage.amount;
110	
111	const payoutForDamage = (item: Item, damage: Damage): number =>
112	  reimbursementOf(item, damage) - DEDUCTIBLE;
113	
114	const claimStep = (step: ClaimStep, policy: QuoteStep): { payout: number; remainingCap: number } => {
115	  const payoutBeforeRounding = step.incident.damages.reduce(
116	    (sum, damage) => sum + payoutForDamage(findInsuredItem(policy, damage.itemType), damage),
117	    0,
118	  );
119	  return { payout: roundDownInMHPCOFavor(payoutBeforeRounding), remainingCap: 0 };
120	};
121	
122	const isQuoteStep = (step: Step): step is QuoteStep => step.op === "quote";
123	
124	export const processScenario = (scenario: unknown): unknown => {
125	  const { customer, steps } = scenario as Scenario;
126	  const results = steps.map((step, index) => {
127	    if (isQuoteStep(step)) {
128	      return quoteStep(step, { customer, isFollowUp: index > 0 });
129	    }
130	    return claimStep(step, steps[step.policy] as QuoteStep);
131	  });
132	  return { results };
133	};
